  "terminologyService.getTerminologyFromCollection" [shape=box];
  "enrichment.addDocument" [shape=box];
  "Neo4j DB" [shape=cylinder];
  "HTTP POST /enrichments/trigger" [shape=ellipse];
  "HTTP GET /enrichments/transaction/:id" [shape=ellipse];

  "POST /documents/:sourceId\n(NestJS Router)" -> "addDocument\n(DocumentController)";
  "addDocument\n(DocumentController)" -> "Logger.log";
  "addDocument\n(DocumentController)" -> "randomUUID";
  "addDocument\n(DocumentController)" -> "asyncHelper.executeAsync";
  "addDocument\n(DocumentController)" -> "documentService.addDocument";
  "addDocument\n(DocumentController)" -> "documentRepository.createDocument";
  "addDocument\n(DocumentController)" -> "markdownService.parse";
  "addDocument\n(DocumentController)" -> "pdfService.import";
  "addDocument\n(DocumentController)" -> "analysisService.addTextAnalysis";
  "addDocument\n(DocumentController)" -> "textService.createTextNodes";
  "addDocument\n(DocumentController)" -> "collectionService.associateDocument";
  "addDocument\n(DocumentController)" -> "terminologyService.getTerminologyFromCollection";
  "addDocument\n(DocumentController)" -> "enrichment.addDocument";
  "documentRepository.createDocument" -> "Neo4j DB" [style=dashed, label="write"];
  "textService.createTextNodes" -> "Neo4j DB" [style=dashed, label="write"];
  "collectionService.associateDocument" -> "Neo4j DB" [style=dashed, label="write/read"];
  "terminologyService.getTerminologyFromCollection" -> "Neo4j DB" [style=dashed, label="read"];
  "enrichment.addDocument" -> "HTTP POST /enrichments/trigger" [style=dashed];
  "enrichment.addDocument" -> "HTTP GET /enrichments/transaction/:id" [style=dashed];
}
```

