**C. Mermaid source**

```mermaid
graph LR
  router["POST /documents/:sourceId (NestJS Router)"] --> FUNC["addDocument (DocumentController)"]
  FUNC --> log["Logger.log"]
  FUNC --> uuid["randomUUID"]
  FUNC --> async["asyncHelper.executeAsync"]
  FUNC --> docSvc["documentService.addDocument"]
  FUNC --> docRepo["documentRepository.createDocument"]
  FUNC --> mdSvc["markdownService.parse"]
  FUNC --> pdfSvc["pdfService.import"]
  FUNC --> analysisSvc["analysisService.addTextAnalysis"]
  FUNC --> textSvc["textService.createTextNodes"]
  FUNC --> collSvc["collectionService.associateDocument"]
  FUNC --> termSvc["terminologyService.getTerminologyFromCollection"]
  FUNC --> enrichSvc["enrichment.addDocument"]
  docRepo -.-> db[("Neo4j DB")]
  textSvc -.-> db
  collSvc -.-> db
  termSvc -.-> db
  enrichSvc -.-> httpPost(["HTTP POST /enrichments/trigger"])
  enrichSvc -.-> httpGet(["HTTP GET /enrichments/transaction/:id"])
```

